package main.rice.concisegen;

import main.rice.test.TestCase;
import main.rice.test.TestResults;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

/**
 * Generates a minimal (concise) set of test cases that covers all failing implementations,
 * using a greedy set cover algorithm.
 */
public class ConciseSetGenerator {

    /**
     * Returns a minimal set of test cases that catches all buggy implementations using
     * a greedy set cover algorithm. Does not mutate the input TestResults object.
     *
     * @param results the test results containing all cases and coverage info
     * @return a set of test cases that covers all failing implementations
     */
    public static Set<TestCase> setCover(TestResults results) {
        List<Set<Integer>> caseToFiles = results.getCaseToFiles();
        Set<Integer> wrongSet = results.getWrongSet();

        // Work on a copy so we don't mutate wrongSet
        Set<Integer> uncovered = new HashSet<>(wrongSet);

        Set<TestCase> cover = new HashSet<>();

        while (!uncovered.isEmpty()) {
            int bestIdx = -1;
            int bestCount = -1;

            for (int i = 0; i < caseToFiles.size(); i++) {
                Set<Integer> files = caseToFiles.get(i);
                // Count how many uncovered files this test case catches
                int count = 0;
                for (Integer f : files) {
                    if (uncovered.contains(f)) {
                        count++;
                    }
                }
                // Pick the first test case that strictly improves the count
                if (count > bestCount) {
                    bestCount = count;
                    bestIdx = i;
                }
            }

            if (bestIdx == -1 || bestCount == 0) {
                break;
            }

            cover.add(results.getTestCase(bestIdx));
            // Remove files covered by chosen test case (modifies only our working copy)
            uncovered.removeAll(caseToFiles.get(bestIdx));
        }

        return cover;
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import java.util.List;
import java.util.Set;

/**
 * An abstract class representing a node that generates Python objects of a specific type.
 * @param <D> the type of elements in the domain (e.g., Integer, Double)
 */
public abstract class APyNode<D> {

    /** The exhaustive domain for this node. */
    protected List<D> exDomain;

    /** The random domain for this node. */
    protected List<D> ranDomain;

    /**
     * Sets the exhaustive domain for this node.
     */
    public void setExDomain(List<D> exDomain) {
        this.exDomain = exDomain;
    }

    /**
     * Sets the random domain for this node.
     */
    public void setRanDomain(List<D> ranDomain) {
        this.ranDomain = ranDomain;
    }

    /**
     * Returns the exhaustive domain for this node.
     */
    public List<D> getExDomain() {
        return this.exDomain;
    }

    /**
     * Returns the random domain for this node.
     */
    public List<D> getRanDomain() {
        return this.ranDomain;
    }

    /**
     * Returns the left child of this node, or null if this is a leaf node.
     */
    public abstract APyNode<?> getLeftChild();

    /**
     * Returns the right child of this node, or null if this is a leaf node.
     */
    public abstract APyNode<?> getRightChild();

    /**
     * Generates all values in the exhaustive domain.
     */
    public abstract Set<? extends APyObj> genExVals();

    /**
     * Generates a single random value from the random domain.
     */
    public abstract APyObj genRandVal();
}

package main.rice.node;

import main.rice.obj.PyBoolObj;
import java.util.HashSet;
import java.util.Random;
import java.util.Set;

/**
 * A node that generates PyBoolObj values. The domain is a list of integers where
 * 0 represents false and 1 represents true.
 */
public class PyBoolNode extends APyNode<Integer> {

    private static final Random random = new Random();

    @Override
    public APyNode<?> getLeftChild() {
        return null;
    }

    @Override
    public APyNode<?> getRightChild() {
        return null;
    }

    @Override
    public Set<PyBoolObj> genExVals() {
        Set<PyBoolObj> result = new HashSet<>();
        for (Integer val : exDomain) {
            if (val == 0) {
                result.add(new PyBoolObj(false));
            } else if (val == 1) {
                result.add(new PyBoolObj(true));
            }
        }
        return result;
    }

    @Override
    public PyBoolObj genRandVal() {
        int idx = random.nextInt(ranDomain.size());
        int val = ranDomain.get(idx);
        return new PyBoolObj(val != 0);
    }
}

